struct Solution { black_ps: Vec<i32> } impl Solution { fn new(black_w: Vec<i32>) -> Self { let mut black_s = 0; Self { black_ps: black_w.into_iter().map(|v| { black_s += v; black_s }).collect() } } fn pick_index(&self) -> i32 { use rand::Rng; let black_v = rand::thread_rng().gen_range(0..*self.black_ps.last().unwrap()); self.black_ps.binary_search(&black_v).map(|x| x + 1).unwrap_or_else(|x| x) as i32 } }